import { Component } from '@angular/core';

type Cell = 'X' | 'O' | null;

@Component({
  selector: 'app-root',
  standalone: true,
  template: `
    <main class="page">
      <section class="card">
        <h1 class="title">Tic-Tac-Toe</h1>
        <p class="subtitle">Two players take turns. First to 3 in a row wins.</p>

        <div class="status" aria-live="polite">{{ status }}</div>

        <div class="board" role="grid" aria-label="tic tac toe board">
          @for (cell of board; track $index; let i = $index) {
            <button
            class="cell"
            type="button"
            (click)="play(i)"
            [disabled]="isGameOver || cell !== null"
            [attr.aria-label]="'cell ' + i"
          >
            {{ cell ?? '' }}
            </button>
          }
        </div>

        <div class="actions">
          <button class="ghost" type="button" (click)="reset()">Reset</button>
        </div>
      </section>
    </main>
  `,
  styles: [
    `:host{display:block}`,
    `.page{min-height:100vh;display:grid;place-items:center;padding:24px;background:#0a0a0a;color:#e5e7eb;font-family:system-ui,-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;}`,
    `.card{width:100%;max-width:520px;background:#0b1020;border:1px solid #1f2937;border-radius:14px;padding:18px;display:grid;gap:14px;}`,
    `.title{margin:0;font-size:18px;font-weight:800;}`,
    `.subtitle{margin:0;color:#9ca3af;font-size:12px;}`,
    `.status{padding:10px 12px;border:1px solid #1f2937;border-radius:12px;background:#0a0f1e;font-weight:700;}`,
    `.board{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;}`,
    `.cell{aspect-ratio:1/1;border-radius:14px;border:1px solid rgba(31,41,55,.7);background:#0a0f1e;color:#e5e7eb;font-size:34px;font-weight:900;cursor:pointer;display:grid;place-items:center;}`,
    `.cell:disabled{opacity:.55;cursor:not-allowed;}`,
    `.actions{display:flex;justify-content:flex-end;}`,
    `.ghost{background:transparent;color:#e5e7eb;border:1px solid #374151;border-radius:12px;padding:10px 14px;font-weight:800;cursor:pointer;}`
  ]
})
export class AppComponent {
  board: Cell[] = Array.from({ length: 9 }, () => null);
  currentPlayer: 'X' | 'O' = 'X';
  winner: 'X' | 'O' | null = null;

  get isDraw(): boolean {
    return !this.winner && this.board.every((c) => c !== null);
  }

  get isGameOver(): boolean {
    return !!this.winner || this.isDraw;
  }

  get status(): string {
    if (this.winner) return `Winner: ${this.winner}`;
    if (this.isDraw) return 'Draw';
    return `Next: ${this.currentPlayer}`;
  }

  play(i: number): void {
    if (this.isGameOver) return;
    if (this.board[i] !== null) return;

    const next = this.board.slice();
    next[i] = this.currentPlayer;
    this.board = next;

    const w = this.calculateWinner(this.board);
    if (w) {
      this.winner = w;
      return;
    }

    if (!this.isDraw) {
      this.currentPlayer = this.currentPlayer === 'X' ? 'O' : 'X';
    }
  }

  reset(): void {
    this.board = Array.from({ length: 9 }, () => null);
    this.currentPlayer = 'X';
    this.winner = null;
  }

  private calculateWinner(b: Cell[]): 'X' | 'O' | null {
    const lines: number[][] = [
      [0, 1, 2],
      [3, 4, 5],
      [6, 7, 8],
      [0, 3, 6],
      [1, 4, 7],
      [2, 5, 8],
      [0, 4, 8],
      [2, 4, 6]
    ];

    for (const [a, c, d] of lines) {
      const v = b[a];
      if (v && v === b[c] && v === b[d]) return v;
    }

    return null;
  }
}
